mapper.select:
SELECT o.INBOUND_ID, o.PLANT_CD, o.INBOUND_NO, o.INBOUND_STATUS, o.VENDOR_CD, o.WAREHOUSE_CD, o.EXPECTED_DT, o.ACTUAL_DT, o.RECEIVE_PLAN_ID, o.INBOUND_RMK, o.REG_USER_ID, o.REG_DTM, o.UPD_USER_ID, o.UPD_DTM, p.PLANT_NM, v.VENDOR_NM, w.WAREHOUSE_NM, c.COM_NM AS INBOUND_STATUS_NM FROM MCS_INBOUND_ORDER o INNER JOIN MST_PLANT p ON o.PLANT_CD = p.PLANT_CD LEFT JOIN MST_VENDOR v ON o.VENDOR_CD = v.VENDOR_CD LEFT JOIN MST_WAREHOUSE w ON o.WAREHOUSE_CD = w.WAREHOUSE_CD LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_IB_STATUS' AND o.INBOUND_STATUS = c.COM_CD
AND o.PLANT_CD = #{plantCd} AND o.VENDOR_CD = #{vendorCd} AND o.WAREHOUSE_CD = #{warehouseCd} AND o.INBOUND_STATUS = #{inboundStatus} AND o.INBOUND_NO LIKE CONCAT('%', #{inboundNo}, '%') AND o.EXPECTED_DT >= #{fromDate} AND o.EXPECTED_DT <= #{toDate}
ORDER BY o.EXPECTED_DT DESC, o.INBOUND_NO DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM MCS_INBOUND_ORDER o

    AND o.PLANT_CD = #{plantCd}
    AND o.VENDOR_CD = #{vendorCd}
    AND o.WAREHOUSE_CD = #{warehouseCd}
    AND o.INBOUND_STATUS = #{inboundStatus}
    AND o.INBOUND_NO LIKE CONCAT('%', #{inboundNo}, '%')
    AND o.EXPECTED_DT >= #{fromDate}
    AND o.EXPECTED_DT <= #{toDate}
